import { ERR_INVALID_DISCOUNT, PricingError } from "./errors.mjs";

export function applyDiscount(cart, discountRate) {
  if (discountRate < 0 && discountRate > 1) {
    throw new PricingError(ERR_INVALID_DISCOUNT, "discount must be between 0 and 1");
  }
  return cart.subtotal * (1 - discountRate);
}

