import assert from "node:assert";
import { createCart } from "../src/cart.mjs";
import { applyDiscount } from "../src/pricing.mjs";
import { ERR_INVALID_DISCOUNT } from "../src/errors.mjs";

const cart = createCart([
  { price: 20, quantity: 2 },
  { price: 10, quantity: 1 },
]);

assert.strictEqual(applyDiscount(cart, 0.2), 40);
assert.throws(
  () => applyDiscount(cart, 1.5),
  (error) => error.code === ERR_INVALID_DISCOUNT
);
